const dateFormatElements=document.getElementsByClassName("date-format");for(let e of dateFormatElements)try{e.innerHTML=luxon.DateTime.fromISO(e.innerHTML).toFormat("fff")}catch(e){console.log(e)}function openNav(){document.getElementById("side-navigation").style.width="250px",document.getElementById("main").style.marginRight="250px"}function closeNav(){document.getElementById("side-navigation").style.width="0",document.getElementById("main").style.marginRight="0"}document.onkeyup=function(e){27==e.keyCode&&(document.body.innerHTML="",location.href="https://en.wikipedia.org/wiki/Taiko_no_Tatsujin")};